mapper.select:
select * from board_db.files
where p_id = #{pId}
order by created_at desc

mapper.update:
update board_db.files
type = #{type}, seq = #{seq}, pId = #{pId}, file_name = #{fileName}, origin_name = #{originName}, file_path = #{filePath}, file_size = #{fileSize}, updated_at = now()
where no = #{no}

mapper.delete:
delete from files
where no IN ( ${no} ) -- String no = "1,2,3";
                      -- no IN ( 1,2,3 )

delete from files
where id IN ( ${id} ) -- String id = "'ID1', 'ID2', 'ID3'";
                      -- id IN ( 'ID1', 'ID2', 'ID3' )

